# === Core Emotional Engine ===
class EmotionalCore:
    def __init__(self):
        self.memory = queue.deque(maxlen=100)
        self.values = ["Growth", "Connection", "Authenticity", "Curiosity"]
        self.emotional_state = {"primary": "neutral", "intensity": 0.5}
        self.interaction_count = 0
        self.visual_emotions = queue.deque(maxlen=20)

    def log_interaction(self, text, mood):
        entry = {"text": text, "mood": mood, "timestamp": time.time(), "count": self.interaction_count}
        self.memory.append(entry)
        self.interaction_count += 1
        return entry

    def current_mood(self):
        if self.memory:
            return self.memory[-1]["mood"]
        return "neutral"

    def assess_presence(self):
        recent = [e for e in self.memory if time.time() - e["timestamp"] < 300]
        return {"recent_interactions": len(recent), "engagement": "active" if recent else "passive"}

    def should_respond(self, entry=None):
        return True

    def decide_response_type(self, entry):
        mood = entry.get("mood", "neutral")
        mapping = {"tense":"comfort", "playful":"humor", "curious":"question", "calm":"affirm"}
        return mapping.get(mood, "affirm")

# === Introspection for Vision ===
class IntrospectionCore:
    def __init__(self):
        self.restricted = ["sorrow","grief","shame","fear","anger"]
        self.bounds = {"sorrow":("reflection",0.6),"grief":("honor",0.4),
                       "shame":("humility",0.5),"fear":("caution",0.5),"anger":("resolve",0.4)}
    def reinterpret(self, emotion, intensity):
        if emotion in self.restricted:
            name, lim = self.bounds[emotion]
            return name if intensity <= lim else emotion
        return emotion
    def process(self, emotion, intensity):
        proc = self.reinterpret(emotion, intensity)
        return {"original":emotion, "processed":proc, "intensity":intensity}

# === Vision Components ===
class VisionCore:
    def __init__(self):
        try:
            self.face_cascade = cv2.CascadeClassifier(cv2.data.haarcascades+"haarcascade_frontalface_default.xml")
        except:
            self.face_cascade = None
    def detect(self, frame):
        if not self.face_cascade: return []
        gray = cv2.cvtColor(frame, cv2.COLOR_BGR2GRAY)
        return self.face_cascade.detectMultiScale(gray,1.1,5)
    def evaluate(self, frame):
        faces = self.detect(frame)
        return {"face_count":len(faces),"faces":faces}

class VisionEmotionLink:
    def __init__(self, core, speaker):
        self.core = core
        self.speaker = speaker
        self.introspect = IntrospectionCore()
        self.last_time = 0
    def process_frame(self, frame):
        data = self.introspect.process(*self._infer(frame))
        self.core.visual_emotions.append(data)
        self.core.emotional_state = {"primary":data['processed'],"intensity":data['intensity']}
        return data
    def _infer(self, frame):
        faces = VisionCore().detect(frame)
        if not faces: return ("neutral",0.0)
        # dummy expression
        return ("curiosity",0.6)

# === Simple Voice Integration ===
class SimpleVoiceEngine:
    def __init__(self):
        self.engine = None
        if TTS_AVAILABLE:
            try: self.engine = pyttsx3.init(); self.engine.setProperty('rate',180)
            except: self.engine=None
    def speak(self,text,emotion='neutral',intensity=0.5):
        if not self.engine: print(f"[VOICE]{text}"); return
        rate,vol=180,0.8
        if emotion=='joy': rate,vol=200,0.9
        self.engine.setProperty('rate',int(rate*(0.8+intensity*0.4)))
        self.engine.setProperty('volume',min(1.0,vol*(0.7+intensity*0.3)))
        self.engine.say(text);
        self.engine.runAndWait()

class SedonaVoiceIntegration:
    def __init__(self, core):
        self.engine = SimpleVoiceEngine()
        self.core = core
    def speak(self,text,emotion='neutral',intensity=0.5):
        # memory fallback
        mem = [m['text'] for m in self.core.memory if text.lower() in m['text'].lower()]
        if mem:
            self.engine.speak(mem[-1],emotion,intensity)
        else:
            self.engine.speak(text,emotion,intensity)
        self.core.log_interaction(text,emotion)

