def detect_mood(text):
    t=text.lower()
    if any(w in t for w in["why","how","?"]): return "curiosity"
    if any(w in t for w in["haha","lol"]): return "playful"
    if any(w in t for w in["angry","damn"]): return "tense"
    return "calm"

